mapper.select:
SELECT sm.`id`, sm.`name`, sm.type, sm.`status`, sm.visible, sm.order_num, sm.icon, sm.path, sm.component, smp.`name` AS parentName FROM `sys_menu` sm LEFT JOIN `sys_menu` smp ON sm.parent_id = smp.id WHERE sm.del_flag = '0'
AND ( sm.name LIKE concat('%', #{request.keyword}, '%') OR sm.path LIKE concat('%', #{request.keyword}, '%')
AND sm.status = #{request.status}
AND sm.type = #{request.type}
AND sm.visible = #{request.visible}
ORDER BY sm.create_time DESC

select t1.id, t1.name, t1.type, t1.`path`, t1.component, t1.order_num, t1.status, t1.visible, exists (select 1 from sys_menu t2 where t2.del_flag = '0' and t2.parent_id = t1.id) as hasChild from sys_menu t1 where t1.del_flag = '0'
and t1.parent_id is null
and t1.parent_id = #{request.parentId}
and (t1.name like #{keywordLike} or t1.`path` like 'keywordLike')
and t1.status = #{request.status}
and t1.`type` = #{request.type}
